34	const PROCESSING_FEE = 5;
35	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
36	
37	const BASE_PREMIUM: Record<string, number> = {
38	  sword: 100,
39	  amulet: 60,
40	  staff: 80,
41	  potion: 40,
42	};
43	
44	const baseFor = (item: Record<string, unknown>): number =>
45	  BASE_PREMIUM[item.type as string] ?? 0;
46	
47	const quotePremium = (step: QuoteStep): StepResult => {
48	  const baseTotal = step.items.reduce((sum, item) => sum + baseFor(item), 0);
49	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
50	  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
51	};
52	
53	const processStep = (step: Step): StepResult => {
54	  if (step.op === "quote") return quotePremium(step);
55	  return { payout: 0, remainingCap: 0 };
56	};
57	
58	export const runScenario = (scenario: Scenario): ScenarioResult => ({
59	  results: scenario.steps.map(processStep),
60	});
